import{_ as o,o as e,c as i,ae as n}from"./chunks/framework.C1F7hH3b.js";const _=JSON.parse('{"title":"串流经验分享，sunshine加moonlight串流，实战教学","description":"","frontmatter":{},"headers":[],"relativePath":"blog/串流经验分享，sunshine加moonlight串流，实战教学.md","filePath":"blog/串流经验分享，sunshine加moonlight串流，实战教学.md","lastUpdated":1780989183000}'),t={name:"blog/串流经验分享，sunshine加moonlight串流，实战教学.md"};function h(l,a,s,r,d,m){return e(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="串流经验分享-sunshine加moonlight串流-实战教学" tabindex="-1">串流经验分享，sunshine加moonlight串流，实战教学 <a class="header-anchor" href="#串流经验分享-sunshine加moonlight串流-实战教学" aria-label="Permalink to &quot;串流经验分享，sunshine加moonlight串流，实战教学&quot;">​</a></h1><p>本篇介绍串流经验分享，记录串流经验，以及串流过程中遇到的问题。</p><h2 id="软件安装" tabindex="-1">软件安装 <a class="header-anchor" href="#软件安装" aria-label="Permalink to &quot;软件安装&quot;">​</a></h2><h3 id="sunshine安装" tabindex="-1">sunshine安装 <a class="header-anchor" href="#sunshine安装" aria-label="Permalink to &quot;sunshine安装&quot;">​</a></h3><h3 id="moonlight安装" tabindex="-1">moonlight安装 <a class="header-anchor" href="#moonlight安装" aria-label="Permalink to &quot;moonlight安装&quot;">​</a></h3><h2 id="串流步骤" tabindex="-1">串流步骤 <a class="header-anchor" href="#串流步骤" aria-label="Permalink to &quot;串流步骤&quot;">​</a></h2><ol><li>启动sunshine</li><li>启动moonlight</li><li>PC和移动端连接同一个wifi</li><li>moonlight客户端会自动搜索到sunshine，点击即可串流</li></ol><h2 id="问题汇总" tabindex="-1">问题汇总 <a class="header-anchor" href="#问题汇总" aria-label="Permalink to &quot;问题汇总&quot;">​</a></h2><h3 id="帧率上不去基本都是30fps" tabindex="-1">帧率上不去基本都是30fps <a class="header-anchor" href="#帧率上不去基本都是30fps" aria-label="Permalink to &quot;帧率上不去基本都是30fps&quot;">​</a></h3><p>sunshine配置项中，设置最小目标帧率，90或者120，视情况而定。</p><h3 id="控制端无法使用模拟的手柄" tabindex="-1">控制端无法使用模拟的手柄 <a class="header-anchor" href="#控制端无法使用模拟的手柄" aria-label="Permalink to &quot;控制端无法使用模拟的手柄&quot;">​</a></h3><p>windows的PC端需要安装ViGEmBus驱动。</p><h3 id="moonlight客户端声音断断续续、出现破音" tabindex="-1">moonlight客户端声音断断续续、出现破音 <a class="header-anchor" href="#moonlight客户端声音断断续续、出现破音" aria-label="Permalink to &quot;moonlight客户端声音断断续续、出现破音&quot;">​</a></h3><p>我的场景是PC和pad都连5G的WiFi，声音破音。</p><p>换成2.4G网络，或者PC端直接插网线，问题就解决了。</p><h3 id="moonlight默认虚拟的手柄不好用" tabindex="-1">moonlight默认虚拟的手柄不好用 <a class="header-anchor" href="#moonlight默认虚拟的手柄不好用" aria-label="Permalink to &quot;moonlight默认虚拟的手柄不好用&quot;">​</a></h3><p>moonlight的安卓端虚拟的手柄太难用了，暂时未解决。</p>',17)])])}const c=o(t,[["render",h]]);export{_ as __pageData,c as default};
